BEGIN;
CREATE TABLE IF NOT EXISTS `migrations` (`id` INT PRIMARY KEY AUTO_INCREMENT NOT NULL, `migration` TEXT NOT NULL, `batch` INT NOT NULL);
CREATE TABLE IF NOT EXISTS `users` (`id` INT PRIMARY KEY AUTO_INCREMENT NOT NULL, `name` TEXT NOT NULL, `email` TEXT, `phone_number` TEXT NOT NULL, `username` TEXT, `email_verified_at` DATETIME, `password` TEXT, `remember_token` TEXT, `created_at` DATETIME, `updated_at` DATETIME, `role` TEXT CHECK (`role` IN ('superadmin', 'profile_manager', 'content_editor', 'user')) NOT NULL DEFAULT 'user', `verification_step` TEXT CHECK (`verification_step` IN ('unverified', 'step1_complete', 'step2_pending', 'approved')) NOT NULL DEFAULT 'unverified', `profile_picture` TEXT);
CREATE TABLE IF NOT EXISTS `password_reset_tokens` (`email` TEXT NOT NULL, `token` TEXT NOT NULL, `created_at` DATETIME, PRIMARY KEY (`email`));
CREATE TABLE IF NOT EXISTS `sessions` (`id` TEXT NOT NULL, `user_id` INT, `ip_address` TEXT, `user_agent` TEXT, `payload` TEXT NOT NULL, `last_activity` INT NOT NULL, PRIMARY KEY (`id`));
CREATE TABLE IF NOT EXISTS `cache` (`key` TEXT NOT NULL, `value` TEXT NOT NULL, `expiration` INT NOT NULL, PRIMARY KEY (`key`));
CREATE TABLE IF NOT EXISTS `cache_locks` (`key` TEXT NOT NULL, `owner` TEXT NOT NULL, `expiration` INT NOT NULL, PRIMARY KEY (`key`));
CREATE TABLE IF NOT EXISTS `jobs` (`id` INT PRIMARY KEY AUTO_INCREMENT NOT NULL, `queue` TEXT NOT NULL, `payload` TEXT NOT NULL, `attempts` INT NOT NULL, `reserved_at` INT, `available_at` INT NOT NULL, `created_at` INT NOT NULL);
CREATE TABLE IF NOT EXISTS `job_batches` (`id` TEXT NOT NULL, `name` TEXT NOT NULL, `total_jobs` INT NOT NULL, `pending_jobs` INT NOT NULL, `failed_jobs` INT NOT NULL, `failed_job_ids` TEXT NOT NULL, `options` TEXT, `cancelled_at` INT, `created_at` INT NOT NULL, `finished_at` INT, PRIMARY KEY (`id`));
CREATE TABLE IF NOT EXISTS `failed_jobs` (`id` INT PRIMARY KEY AUTO_INCREMENT NOT NULL, `uuid` TEXT NOT NULL, `connection` TEXT NOT NULL, `queue` TEXT NOT NULL, `payload` TEXT NOT NULL, `exception` TEXT NOT NULL, `failed_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP());
CREATE TABLE IF NOT EXISTS `user_profile` (`id` INT PRIMARY KEY AUTO_INCREMENT NOT NULL, `user_id` INT NOT NULL, `full_name` TEXT, `navras_naav` TEXT, `gender` TEXT, `education` TEXT, `occupation` TEXT, `annual_income` DECIMAL, `date_of_birth` DATE, `day_and_time_of_birth` TEXT, `place_of_birth` TEXT, `jaath` TEXT, `height_cm__Oonchi` TEXT, `skin_complexion__Rang` TEXT, `zodiac_sign__Raas` TEXT, `naadi` TEXT, `gann` TEXT, `devak` TEXT, `kul_devata` TEXT, `fathers_name` TEXT, `mothers_name` TEXT, `marital_status` TEXT, `siblings` TEXT, `uncles` TEXT, `aunts` TEXT, `mumbai_address` TEXT, `village_address` TEXT, `village_farm` TEXT, `naathe_relationships` TEXT, `weight_kg` DECIMAL, `created_at` DATETIME, `updated_at` DATETIME, `primary_image` INT NOT NULL DEFAULT '1', FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON delete CASCADE);
CREATE TABLE IF NOT EXISTS `edit_user_profiles` (`id` INT PRIMARY KEY AUTO_INCREMENT NOT NULL, `user_id` INT NOT NULL, `full_name` TEXT, `navras_naav` TEXT, `gender` TEXT, `education` TEXT, `occupation` TEXT, `annual_income` DECIMAL, `date_of_birth` DATE, `day_and_time_of_birth` TEXT, `place_of_birth` TEXT, `jaath` TEXT, `height_cm__Oonchi` TEXT, `skin_complexion__Rang` TEXT, `zodiac_sign__Raas` TEXT, `naadi` TEXT, `gann` TEXT, `devak` TEXT, `kul_devata` TEXT, `fathers_name` TEXT, `mothers_name` TEXT, `marital_status` TEXT, `siblings` TEXT, `uncles` TEXT, `aunts` TEXT, `mumbai_address` TEXT, `village_address` TEXT, `village_farm` TEXT, `naathe_relationships` TEXT, `status` TEXT CHECK (`status` IN ('pending', 'approved', 'rejected')) NOT NULL DEFAULT 'pending', `created_at` DATETIME, `updated_at` DATETIME, FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON delete CASCADE);
CREATE UNIQUE INDEX `users_email_unique` ON `users`(`email`);
CREATE UNIQUE INDEX `users_phone_number_unique` ON `users`(`phone_number`);
CREATE UNIQUE INDEX `users_username_unique` ON `users`(`username`);
CREATE INDEX `sessions_user_id_index` ON `sessions`(`user_id`);
CREATE INDEX `sessions_last_activity_index` ON `sessions`(`last_activity`);
CREATE INDEX `cache_expiration_index` ON `cache`(`expiration`);
CREATE INDEX `cache_locks_expiration_index` ON `cache_locks`(`expiration`);
CREATE INDEX `jobs_queue_index` ON `jobs`(`queue`);
CREATE UNIQUE INDEX `failed_jobs_uuid_unique` ON `failed_jobs`(`uuid`);
COMMIT;
